var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아빠! 오늘은 언제 놀아줘?","JPN":"パパ！　今日はいつ遊んでくれるの？","ENG":"Daddy! When can you play with me today?","TWN":"爸爸！今天不陪我玩嗎？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오늘은 안돼. 아빠는 돈을 버느라 바쁘단다.","JPN":"今日はダメだ。パパはお金を稼ぐのに忙しいんだよ。","ENG":"Not today. Daddy's busy making money.","TWN":"今天不行喔，爸爸要去賺錢。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그럼 내가 도와줄게! 조폐소를 우리 걸로 만들자!","JPN":"それなら私が助けてあげる！　造幣局を私たちのものに\\nしようよ！","ENG":"Oooh, then how about I help you? Let's take over the mint!","TWN":"那我幫你！我們去搶造幣廠吧！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그러면 굳이 돈을 벌 필요도 없잖아!","JPN":"そうすれば、お金を稼がなくて済むでしょ？","ENG":"Then, you don't have to work hard.","TWN":"那樣就不需要賺錢了！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그건 범죄란다. 아빤 결코 돈을 위해서 비리나 범죄를 저지르지 않아요.","JPN":"それは犯罪だよ。パパは決してお金のために犯罪を\\n犯したりはしないんだ。","ENG":"That's a crime. Your daddy is never going to commit crimes or corrupt acts to make money.","TWN":"那是犯罪，爸爸絕對不會為了掙錢而做非法勾當或犯罪。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아빠처럼 청렴한 인물은 스스로의 힘으로 돈을 버는 것에 자부심을 느끼거든.","JPN":"パパのように清廉潔白な人は、みずからの力でお金を稼ぐことに自負心を持っているんだ。","ENG":"Your daddy is an honest person, and honest people work hard to earn their money.","TWN":"像爸爸這樣清廉的人要憑藉自己的努力賺錢才有意義。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"범죄구나! 알겠어!","JPN":"犯罪なのね！　わかった！","ENG":"It's a crime, got it.","TWN":"原來是犯罪！知道了！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그럼 나도 아빠처럼 정직하게 돈을 벌게!","JPN":"じゃあ私もパパみたいに真面目にお金を稼ぐよ！","ENG":"Then, I want to earn money honestly like you.","TWN":"那我也要像爸爸一樣誠實地賺錢！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"난 뭘 하면 될까? 응?","JPN":"私は何をすればいいのかな？　ねえねえ。","ENG":"How can I do that? Mm?","TWN":"那我該做什麼呢？嗯？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐음.","JPN":"ふむ。","ENG":"Hmm...","TWN":"唔。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그래, 언젠가 네가 이 회사를 물려받게 될지도 모르니 후계자 수업을 해보는 것도 좋겠구나.","JPN":"そうだな、いつか君がこの会社を引き継ぐかも\\nしれないから、後継者教育を受けておくと良いかもしれない。","ENG":"Well, one day I might decide to hand this company over to you. Maybe I should start training you for that.","TWN":"對了，你以後可能要繼承這家公司，現在不如上一些接班人課程吧。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"물려...... 받아?","JPN":"引き……継ぐ？","ENG":"Hand it over to me.","TWN":"接……班？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그냥 아빠가 계속 하면 안돼?","JPN":"パパがずっと続けるのはダメなの？","ENG":"Why can't you keep it?","TWN":"爸爸一直做下去不行嗎？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"사람 일이란 게 앞으로 어떻게 될지 모르는 일이잖니.","JPN":"人生は、いつどうなるかわからないからな。","ENG":"Because we don't know what might happen in the future.","TWN":"但是世事難料呀。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"날 두고 떠나진 않을 거지? 응?","JPN":"私のこと、置いて行ったりしないよね？　そうだよね？","ENG":"You're not going to leave me, are you?","TWN":"爸爸不會離開我吧？對不對？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"물론이지~ 아빠는 언제까지고 계속 여기 있을 거란다.","JPN":"もちろんだ～。パパはいつまでもここにいるよ。","ENG":"Of course not. Daddy is always going to be here for you.","TWN":"當然～爸爸會永遠在你身邊。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하지만 시그마. 너도 아빠가 하는 일을 배우면 아빠를 도와줄 수도 있겠지?","JPN":"だがシグマ。君がパパの仕事を覚えれば、パパのことを手伝ったりもできるだろう？","ENG":"But Sigma, if you learn what Daddy does, you can help him.","TWN":"不過西格瑪，你如果學到了爸爸的工作，以後就能幫爸爸更多的忙喔？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응, 아빠를 도와주는 거라면 뭐든지 할게!","JPN":"うん、パパの助けになるならなんでもやる！","ENG":"Okay, I can do anything to help you, Daddy.","TWN":"嗯，只要能幫到爸爸，我什麼都願意做！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"뭐부터 배우면 될까?","JPN":"何から覚えれば良いのかな？","ENG":"Where do you want me to start?","TWN":"那先從什麼開始呢？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};